// Generated by Wrangler by running `wrangler types`
// (manually extended with secrets — `wrangler types` does not emit secret bindings)

interface Env {
	// Secret, set via `wrangler secret put YOUTUBE_API_KEY`. Backs GET /team-videos:
	// resolves each club's YouTube uploads + recent videos via the YouTube Data API.
	YOUTUBE_API_KEY: string;

	// Secret, set via `wrangler secret put ANTHROPIC_API_KEY`. Backs the Feed's
	// per-post Claude Haiku relevance/no-hot-takes filter (Step 2). When unset, the
	// filter fails open for curated Bluesky handles (the Feed serves unfiltered).
	ANTHROPIC_API_KEY?: string;

	// KV namespace caching one Haiku verdict per post id (bsky:{uri}), ~7d TTL —
	// a post is tagged ONCE, ever; only never-seen posts hit Haiku on a cache miss.
	// Also holds the B3b social-cards snapshot (SOCIAL_CACHE_KEY), refreshed by cron.
	FEED_TAGS: KVNamespace;

	// Secret, set via `wrangler secret put APIFY_TOKEN`. Backs the B3b IG/TikTok
	// social pipe: the daily cron calls Apify's low-cost IG + TikTok scrapers for
	// curated club + player handles and caches the resulting cards in KV. When unset,
	// the social builder yields [] (Home/Feed fall back to seed for those cards) —
	// every other source is unaffected.
	APIFY_TOKEN?: string;

	// Sign in with Apple (SIWA) revocation — secrets set via `wrangler secret put`.
	// Back POST /auth/apple-token-exchange + the account-delete revoke step: the .p8
	// signs an ES256 client_secret JWT used against Apple's /auth/token + /auth/revoke.
	// Distinct from the match-watcher's APNs key. When unset, the exchange endpoint 500s
	// (health-gated) and account deletion skips revoke (Supabase delete still proceeds).
	//   SIWA_PRIVATE_KEY  the .p8 private key, full PEM text   (Apple)
	//   SIWA_KEY_ID       the .p8's 10-char Key ID             (Apple)
	//   APPLE_TEAM_ID     Apple Developer Team ID              (Apple)
	SIWA_PRIVATE_KEY?: string;
	SIWA_KEY_ID?: string;
	APPLE_TEAM_ID?: string;
}
